(673, 'Trop Kick', 70, 0, 0, 'Grass', '0', '1', '100', 'Attack_down', 0, '', 1, '', '', '', 'The user lands an intense kick of tropical origins on the target. This also lowers the target’s Attack stat.', 'ja', 'Physical', b'0', 688, b'1', b'0'),
