(675, 'Zing Zap', 80, 0, 0, 'Electric', '0', '1', '30', 'Flinch', 0, '', 1, '', '', '', 'A strong electric blast crashes down on the target, giving it an electric shock. This may also make the target flinch.', 'ja', 'Physical', b'0', 716, b'1', b'0'),
(676, '10,000,000 Volt Thunderbolt', 195, 0, 1, 'Electric', '0', '1', '100', 'Attack_up', 0, '', 1, '', '', '', 'Hard, pointed, sharp claws rake the target to inflict damage.', '', 'Special', b'1', 719, b'1', b'1'),
(677, 'Acid Downpour', 0, 0, 0, 'Poison', '0', '1', '', '', 0, '', 1, '', '', '', 'The user creates a poisonous swamp using its Z-Power and sinks the target into it at full force. The power varies, depending on the original move.', '', 'Varies', b'1', 628, b'1', b'1'),
(678, 'All-Out Pummeling', 0, 0, 0, 'Fighting', '0', '1', '', '', 0, '', 1, '', '', '', 'The user rams an energy orb created by its Z-Power into the target with full force. The power varies, depending on the original move.', '', 'Varies', b'1', 624, b'1', b'1'),
(679, 'Black Hole Eclipse', 0, 0, 0, 'Dark', '0', '1', '', '', 0, '', 1, '', '', '', 'The user gathers dark energy using its Z-Power and sucks the target into it. The power varies, depending on the original move.', '', 'Varies', b'1', 654, b'1', b'1'),
(680, 'Bloom Doom', 0, 0, 0, 'Grass', '0', '1', '', '', 0, '', 1, '', '', '', 'The user collects energy from plants using its Z-Power and attacks the target with full force. The power varies, depending on the original move.', '', 'Varies', b'1', 644, b'1', b'1'),
(681, 'Breakneck Blitz', 0, 0, 0, 'Normal', '0', '1', '', '', 0, '', 1, '', '', '', 'The user builds up its momentum using its Z-Power and crashes into the target at full speed. The power varies, depending on the original move.', '', 'Varies', b'1', 622, b'1', b'1'),
(682, 'Catastropika', 210, 0, 0, 'Electric', '0', '1', '', '', 0, '', 1, '', '', '', 'The user, Pikachu, surrounds itself with the maximum amount of electricity using its Z-Power and pounces on its target with full force.', '', 'Physical', b'1', 658, b'1', b'1'),
(683, 'Clangorous Soulblaze', 185, 0, 0, 'Dragon', '0', '1', '100', 'All_up', 0, '', 1, '', '', '', 'After obtaining Z-Power, the user, Kommo-o, attacks the opposing Pokémon with full force. This move boosts the user’s stats.', '', 'Special', b'1', 728, b'1', b'1'),
(684, 'Continental Crush', 0, 0, 0, 'Rock', '0', '1', '', '', 0, '', 1, '', '', '', 'The user summons a huge rock mountain using its Z-Power and drops it onto the target with full force. The power varies, depending on the original move.', '', 'Varies', b'1', 632, b'1', b'1'),
(685, 'Corkscrew Crash', 0, 0, 0, 'Steel', '0', '1', '', '', 0, '', 1, '', '', '', 'The user spins very fast and rams into the target with the full force of its Z-Power. The power varies, depending on the original move.', '', 'Varies', b'1', 638, b'1', b'1'),
(686, 'Devastating Drake', 0, 0, 0, 'Dragon', '0', '1', '', '', 0, '', 1, '', '', '', 'The user materializes its aura using its Z-Power and attacks the target with full force. The power varies, depending on the original move.', '', 'Varies', b'1', 652, b'1', b'1'),
(687, 'Extreme Evoboost', 0, 0, 0, 'Normal', '0', '1', '100', 'All_up', 0, '', 1, '', '', '', 'After obtaining Z-Power, the user, Eevee, gets energy from its evolved friends and boosts its stats sharply.', '', 'Status', b'1', 702, b'1', b'1'),
(688, 'Genesis Supernova', 185, 0, 0, 'Psychic', '0', '1', '', '', 0, '', 1, '', '', '', 'After obtaining Z-Power, the user, Mew, attacks the target with full force. The terrain will be charged with psychic energy.', '', 'Special', b'1', 703, b'1', b'1'),
(689, 'Gigavolt Havoc', 0, 0, 0, 'Electric', '0', '1', '', '', 0, '', 1, '', '', '', 'The user hits the target with a powerful electric current collected by its Z-Power. The power varies, depending on the original move.', '', 'Varies', b'1', 646, b'1', b'1'),
(690, 'Guardian of Alola', 1, 0, 0, 'Fairy', '0', '1', '', '', 0, '', 1, '', '', '', 'The user, the Land Spirit Pokémon, obtains Alola’s energy using its Z-Power and attacks the target with full force. This reduces the target’s HP greatly.', '', 'Special', b'1', 698, b'1', b'1'),
(691, 'Hydro Vortex', 0, 0, 0, 'Water', '0', '1', '', '', 0, '', 1, '', '', '', 'The user creates a huge whirling current using its Z-Power to swallow the target with full force. The power varies, depending on the original move.', '', 'Varies', b'1', 642, b'1', b'1'),
(692, 'Inferno Overdrive', 0, 0, 0, 'Fire', '0', '1', '', '', 0, '', 1, '', '', '', 'The user breathes a stream of intense fire toward the target with the full force of its Z-Power. The power varies depending on the original move.', '', 'Varies', b'1', 640, b'1', b'1'),
(693, 'Lets Snuggle Forever', 190, 0, 0, 'Fairy', '0', '1', '', '', 0, '', 1, '', '', '', 'After obtaining Z-Power, the user, Mimikyu, punches the target with full force.', '', 'Physical', b'1', 726, b'1', b'1'),
(694, 'Light That Burns the Sky', 200, 0, 0, 'Psychic', '0', '1', '', '', 0, '', 1, '', '', '', 'This attack inflicts Attack or Sp. Atk damage— whichever stat is higher for the user, Necrozma. This move ignores the target’s Ability.', '', 'Special', b'1', 723, b'1', b'1'),
(695, 'Malicious Moonsault', 180, 0, 0, 'Dark', '0', '1', '', '', 0, '', 1, '', '', '', 'The user, Incineroar, strengthens its body using its Z-Power and crashes into the target with full force.', '', 'Physical', b'1', 696, b'1', b'1'),
(696, 'Menacing Moonraze Maelstrom', 200, 0, 0, 'Ghost', '0', '1', '', '', 0, '', 1, '', '', '', 'After obtaining Z-Power, the user, Lunala, attacks the target with full force. This move can ignore the effect of the target’s Ability.', '', 'Special', b'1', 725, b'1', b'1'),
(697, 'Never-Ending Nightmare', 0, 0, 0, 'Ghost', '0', '1', '', '', 0, '', 1, '', '', '', 'Deep-seated grudges summoned by the user’s Z-Power trap the target. The power varies, depending on the original move.', '', 'Varies', b'1', 636, b'1', b'1'),
(698, 'Oceanic Operetta', 195, 0, 0, 'Water', '0', '1', '', '', 0, '', 1, '', '', '', 'The user, Primarina, summons a massive amount of water using its Z-Power and attacks the target with full force.', '', 'Special', b'1', 697, b'1', b'1'),
(699, 'Pulverizing Pancake', 210, 0, 0, 'Normal', '0', '1', '', '', 0, '', 1, '', '', '', 'Z-Power brings out the true capabilities of the user, Snorlax. The Pokémon moves its enormous body energetically and attacks the target with full force.', '', 'Physical', b'1', 701, b'1', b'1'),
(700, 'Savage Spin-Out', 0, 0, 0, 'Bug', '0', '1', '', '', 0, '', 1, '', '', '', 'The user binds the target with full force with threads of silk that the user spits using its Z-Power. The power varies, depending on the original move.', '', 'Varies', b'1', 634, b'1', b'1'),
(701, 'Searing Sunraze Smash', 200, 0, 0, 'Steel', '0', '1', '', '', 0, '', 1, '', '', '', 'After obtaining Z-Power, the user, Solgaleo, attacks the target with full force. This move can ignore the effect of the target’s Ability.', '', 'Physical', b'1', 724, b'1', b'1'),
(702, 'Shattered Psyche', 0, 0, 0, 'Psychic', '0', '1', '', '', 0, '', 1, '', '', '', 'The user controls the target with its Z-Power and hurts the target with full force. The power varies, depending on the original move.', '', 'Varies', b'1', 648, b'1', b'1'),
(703, 'Sinister Arrow Raid', 180, 0, 0, 'Ghost', '0', '1', '', '', 0, '', 1, '', '', '', 'The user, Decidueye, creates countless arrows using its Z-Power and shoots the target with full force.', '', 'Physical', b'1', 695, b'1', b'1'),
(704, 'Soul-Stealing 7-Star Strike', 195, 0, 0, 'Ghost', '0', '1', '', '', 0, '', 1, '', '', '', 'After obtaining Z-Power, the user, Marshadow, punches and kicks the target consecutively with full force.', '', 'Physical', b'1', 699, b'1', b'1'),
(705, 'Splintered Stormshards', 190, 0, 0, 'Rock', '0', '1', '', '', 0, '', 1, '', '', '', 'After obtaining Z-Power, the user, Lycanroc, attacks the target with full force. This move negates the effect on the battlefield.', '', 'Physical', b'1', 727, b'1', b'1'),
(706, 'Stoked Sparksurfer', 175, 0, 0, 'Electric', '0', '1', '100', 'Paralyzed', 0, '', 1, '', '', '', 'After obtaining Z-Power, the user, Alolan Raichu, attacks the target with full force. This move leaves the target with paralysis.', '', 'Special', b'1', 700, b'1', b'1'),
(707, 'Subzero Slammer', 0, 0, 0, 'Ice', '0', '1', '', '', 0, '', 1, '', '', '', 'The user dramatically drops the temperature using its Z-Power and freezes the target with full force. The power varies, depending on the original move.', '', 'Varies', b'1', 650, b'1', b'1'),
(708, 'Supersonic Skystrike', 0, 0, 0, 'Flying', '0', '1', '', '', 0, '', 1, '', '', '', 'The user soars up with its Z-Power and plummets toward the target at full speed. The power varies, depending on the original move.', '', 'Varies', b'1', 626, b'1', b'1'),
(709, 'Tectonic Rage', 0, 0, 0, 'Ground', '0', '1', '', '', 0, '', 1, '', '', '', 'The user burrows deep into the ground and slams into the target with the full force of its Z-Power. The power varies, depending on the original move.', '', 'Varies', b'1', 630, b'1', b'1'),
(710, 'Twinkle Tackle', 0, 0, 0, 'Fairy', '0', '1', '', '', 0, '', 1, '', '', '', 'The user creates a very charming space using its Z-Power and totally toys with the target. The power varies, depending on the original move.', '', 'Varies', b'1', 656, b'1', b'1'),
(711, 'Double Iron Bash', 60, 0, 0, 'Steel', '0', '2', '30', 'Flinch', 1, '', 1, '', '', '', '', 'ja', 'Physical', b'1', 742, b'1', b'0');
