INSERT INTO `huizen` (`id`, `afkorting`, `kosten`, `ruimte`, `link`, `omschrijving_nl`, `omschrijving_en`, `omschrijving_de`, `omschrijving_es`, `omschrijving_pl`) VALUES
(1, 'doos', 500, 2, 'images/house1.png', 'Een <b>kartonnen doos</b>. Deze vind je vaak bij de pokemarkt.<br>\nHierin kun je 2 Pokemons houden.', 'A <b>Caixa de Papelão</b>. Uma caixa extremamente simples.<br>\r\nAqui cabem ate 2 pokemons.', 'A <b>hamper box</b>. These you can find in the pokemarket.<br>\r\nIn the box can stay 2 pokemon.', 'A <b>hamper box</b>. These you can find in the pokemarket.<br>\r\nIn the box can stay 2 pokemon.', 'A <b>hamper box</b>. These you can find in the pokemarket.<br>\r\nIn the box can stay 2 pokemon.'),
(2, 'shuis', 3000, 20, 'images/house2.gif', 'Een <b>klein huis</b>. Geschikt voor een pokemon trainer als beginner.<br>\r\nHierin kun je 20 Pokemon houden.', 'A <b>Casa Pequena</b>. Uma casa muito popular entre os treinadores iniciantes.<br>\nAqui cabem ate 20 pokemons.', 'A <b>little house</b>. This house is popular for the beginning trainers.<br>\nIn the small house can stay 20 pokemon.', 'A <b>little house</b>. This house is popular for the beginning trainers.<br>\r\nIn the small house can stay 20 pokemon.', 'A <b>little house</b>. This house is popular for the beginning trainers.<br>\r\nIn the small house can stay 20 pokemon.'),
(3, 'nhuis', 30000, 100, 'images/house3.gif', 'Een <b>normaal huis</b> met een grote tuin en vijver waar de Pokemons in kunnen zwemmen.<br>\r\nHierin kun je 100 Pokemons houden.', 'A <b>Casa Normal</b>. Uma bela casa com jardim e um lago com peixes, seus pokemons irao adorar.<br>\nAqui cabem ate 100 pokemons.', 'A <b>normal house</b> with a garden and a fish pond. The pokemon can play here.<br>\r\nIn the normal house can stay 100 pokemon.', 'A <b>normal house</b> with a garden and a fish pond. The pokemon can play here.<br>\r\nIn the normal house can stay 100 pokemon.', 'A <b>normal house</b> with a garden and a fish pond. The pokemon can play here.<br>\r\nIn the normal house can stay 100 pokemon.'),
(4, 'villa', 80000, 2500, 'images/house4.gif', 'Een <b>villa</b> met een hele grote tuin en een mega zwembad waar de Pokemons in kunnen zwemmen.\nHierin kun je 2500 Pokemons houden.', 'A <b>Mansao</b>. Uma imensa propiedade com campo aberto e um lindo jardim com lagos majestosos.\nAqui cabem ate 2500 pokemons.', '', '', '');
