INSERT INTO `official_message` (`id`, `title`, `message`, `admin`, `date`, `hidden`) VALUES
(1, 'Seja bem-vindo(a) ao Pokémon World Legends!', '&lt;p style=&quot;text-align: center;&quot;&gt;Ol&amp;aacute; &lt;strong&gt;treinador&lt;/strong&gt;! Seja bem-vindo(a) ao Pok&amp;eacute;mon World Legends!&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/003.png&quot; alt=&quot;003&quot; /&gt;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;Recompensas&lt;/strong&gt;:&amp;nbsp;&lt;/p&gt;\r\n&lt;ul style=&quot;text-align: center;color:white;&quot;&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;3 dias de PREMIUM!&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;5x Pok&amp;eacute;Ball;&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;1x Potion;&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;5.000 Silvers.&lt;/li&gt;\r\n&lt;/ul&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;Capture +900 Esp&amp;eacute;cies do Pok&amp;eacute;mon diferentes, fa&amp;ccedil;a novas amizades, enfrente seus rivais, participe dos Torneios e da famosa&amp;nbsp;&lt;strong&gt;Liga Pok&amp;eacute;mon&lt;/strong&gt;, jogue os eventos, e muito mais!&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;Espero que voc&amp;ecirc;s gostem da jornada e que a cada dia possamos evoluir juntos.&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;E sigam nossas Redes Sociais ao lado (@pkworldlegends).&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;Voc&amp;ecirc; se acha capaz de se tornar o melhor treinador Pok&amp;eacute;mon?&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/003.png&quot; alt=&quot;003&quot; /&gt;&lt;/p&gt;', 1, '27/04/2019', b'0'),
(3, 'Notas de Atualização 1.1', '&lt;p style=&quot;text-align: center;&quot;&gt;Ol&amp;aacute;, obrigado por aguardarem a &lt;strong&gt;manunten&amp;ccedil;&amp;atilde;o&lt;/strong&gt;!&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/003.png&quot; alt=&quot;003&quot; /&gt;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;Para voc&amp;ecirc;s se manterem informados, iremos postar as &lt;strong&gt;Notas de Atualiza&amp;ccedil;&amp;otilde;es&lt;/strong&gt; dessa Vers&amp;atilde;o do &lt;strong&gt;Pok&amp;eacute;mon World Legends!&lt;/strong&gt;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;Vamos l&amp;aacute;!&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/005.png&quot; alt=&quot;005&quot; /&gt;&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ol style=&quot;text-align: center;color:white;&quot;&gt;\r\n&lt;li style=&quot;text-align: center;color:white;&quot;&gt;Cria&amp;ccedil;&amp;atilde;o do Novo Pacote:&lt;strong&gt; Starter Pack&lt;/strong&gt;! Confira aqui:&amp;nbsp;&lt;a href=&quot;../donate&quot;&gt;https://www.pokemonworldlegends.com/donate&lt;/a&gt;&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;O t&amp;atilde;o pedido &lt;strong&gt;reajuste&amp;nbsp;&lt;/strong&gt;na &lt;strong&gt;Calculadora&lt;/strong&gt;! Diminuimos o pre&amp;ccedil;o por tentativa e limite!&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;Diminuimos o pre&amp;ccedil;o dos golpes aprendidos no&lt;strong&gt; Move Tutor&lt;/strong&gt;.&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;Ap&amp;oacute;s alguns relatos de dificuldade em pegar os&lt;strong&gt; OVNIs&amp;nbsp;&lt;/strong&gt;decidimos reduzir a velocidade deles. Agora est&amp;atilde;o um pouco mais lentos...&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/016.png&quot; alt=&quot;016&quot; /&gt;&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;Alola&amp;nbsp;&lt;/strong&gt;foi uma regi&amp;atilde;o um tanto problem&amp;aacute;tica, e por isso tivemos que ajeitar um problema recorrente na &quot;Torre Fantasma&quot; da regi&amp;atilde;o, como tamb&amp;eacute;m a evolu&amp;ccedil;&amp;atilde;o do &lt;strong&gt;Alolan Marowak e Alolan Exeggutor!&lt;/strong&gt;&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;Outra modifica&amp;ccedil;&amp;atilde;o em&amp;nbsp;&lt;strong&gt;Alola&lt;/strong&gt; foi a adi&amp;ccedil;&amp;atilde;o de alguns Pok&amp;eacute;mons que n&amp;atilde;o haviam no mapa. Confiram na Pok&amp;eacute;Dex!&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/008.png&quot; alt=&quot;008&quot; /&gt;&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;EGGS Pok&amp;eacute;mon RAROS,&lt;/strong&gt; estavam um pouco caros, ent&amp;atilde;o resolvemos diminuir o pre&amp;ccedil;o deles em&amp;nbsp;&lt;strong&gt;Gold&lt;/strong&gt;, como tamb&amp;eacute;m, haviam alguns relatos de Pok&amp;eacute;mon n&amp;atilde;o-lend&amp;aacute;rios aparecendo neles e fizemos esta altera&amp;ccedil;&amp;atilde;o.&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;[MINI-EVENTO] 3x EXP &amp;amp; 3x SILVERS ADICIONADOS AT&amp;Eacute; O DIA 04/05/2019! (Feliz dia do Trabalho!)&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/001.png&quot; alt=&quot;001&quot; /&gt;&lt;/strong&gt;&lt;br /&gt;&lt;br /&gt;Encerramos essa Nota de Atualiza&amp;ccedil;&amp;atilde;o por aqui!&lt;br /&gt;Obrigado pela leitura e pelo aguardo pela manunten&amp;ccedil;&amp;atilde;o!&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/013.png&quot; alt=&quot;013&quot; /&gt;&lt;br /&gt;&lt;br /&gt;Atenciosamente:&lt;strong&gt; Pok&amp;eacute;mon World Legends&lt;/strong&gt;!&lt;/li&gt;\r\n&lt;/ol&gt;', 1, '01/05/2019', b'1'),
(4, 'Notas de Atualização 1.2', '&lt;p style=&quot;text-align: center;&quot;&gt;Ol&amp;aacute;, Treinadores! Obrigado por aguardarem a &lt;strong&gt;manunten&amp;ccedil;&amp;atilde;o!&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/002.png&quot; alt=&quot;002&quot; /&gt;&lt;/strong&gt;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;Como de costume abaixo, voc&amp;ecirc; treinador poder&amp;aacute; conferir quais foram as &lt;strong&gt;Notas de Atualiza&amp;ccedil;&amp;otilde;es&lt;/strong&gt; dessa Vers&amp;atilde;o de &lt;strong&gt;Pok&amp;eacute;mon World Legends!&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/009.png&quot; alt=&quot;009&quot; /&gt;&lt;/strong&gt;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;Ent&amp;atilde;o confira!&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/007.png&quot; alt=&quot;007&quot; /&gt;&lt;/strong&gt;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;1. &lt;strong&gt;Resolvido&lt;/strong&gt; o bug relatado pelos treinadores sobre, o mau funcionamento dos status (&lt;em&gt;&lt;strong&gt;Sleep, Frozen, Paralize&lt;/strong&gt;&lt;/em&gt;);&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/003.png&quot; alt=&quot;003&quot; /&gt;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;2. Novas &lt;strong&gt;anima&amp;ccedil;&amp;otilde;e&lt;/strong&gt;s de &lt;strong&gt;golpes&lt;/strong&gt; nas batalhas &lt;strong&gt;adicionadas&lt;/strong&gt;;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;3. &lt;strong&gt;Corrigido&lt;/strong&gt; um pequeno bug nos &lt;strong&gt;Leil&amp;otilde;es&lt;/strong&gt;;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;4. &lt;strong&gt;Promo&amp;ccedil;&amp;atilde;o Pok&amp;eacute;mon M&amp;iacute;tico&lt;/strong&gt; pertencente aos packs acima de R$64,00 &lt;strong&gt;removido&lt;/strong&gt;;&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/011.png&quot; alt=&quot;011&quot; /&gt;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;5. Adicionada na &lt;strong&gt;Pok&amp;eacute;dex&lt;/strong&gt; de batalha, o ganho de &lt;strong&gt;EV\'s&lt;/strong&gt; obtidas em nos combates contra &lt;strong&gt;pok&amp;eacute;mons selvagens&lt;/strong&gt;;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;6. &lt;strong&gt;HM\'s&lt;/strong&gt; adicionadas aos pok&amp;eacute;mons de &lt;strong&gt;Alola&lt;/strong&gt;;&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/013.png&quot; alt=&quot;013&quot; /&gt;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;7. A &lt;strong&gt;Pok&amp;eacute;dex&lt;/strong&gt; agora possuiu uma nova funcionalidade, que revela se o pok&amp;eacute;mon em exibi&amp;ccedil;&amp;atilde;o pode ser obtido nos &lt;strong&gt;Egg\'s&lt;/strong&gt; da &lt;strong&gt;PokeMart&lt;/strong&gt;;&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/019.png&quot; alt=&quot;019&quot; /&gt;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;8. &lt;strong&gt;Modifica&amp;ccedil;&amp;atilde;o&lt;/strong&gt; de algumas imagens de &lt;strong&gt;pok&amp;eacute;mons&lt;/strong&gt; e &lt;strong&gt;itens&lt;/strong&gt;;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;9. &lt;strong&gt;Adicionado!&lt;/strong&gt; &lt;em&gt;O Primeiro Evento de Pok&amp;eacute;mon World Legends:&lt;/em&gt; &lt;span style=&quot;text-decoration: underline;&quot;&gt;&lt;strong&gt;&lt;em&gt;DROP ELEMENTAL&lt;/em&gt;&lt;/strong&gt;&lt;/span&gt;.&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/004.png&quot; alt=&quot;004&quot; /&gt;&lt;/p&gt;', 3, '04/05/2019', b'1'),
(5, 'Conjunto de DROPS - Drops Elementais', '&lt;p style=&quot;text-align: center;&quot;&gt;Ol&amp;aacute; &amp;agrave; todos!&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/003.png&quot; alt=&quot;003&quot; /&gt;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;Estamos aqui para informar sobre o&amp;nbsp;&lt;strong&gt;Conjunto de DROPS!&lt;/strong&gt;&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/007.png&quot; alt=&quot;007&quot; /&gt;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;O que seria esse tal&amp;nbsp;&lt;strong&gt;Conjunto de DROPS?&lt;/strong&gt;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;Por apenas &lt;strong&gt;50 Golds&amp;nbsp;&lt;/strong&gt;voc&amp;ecirc; pode adquirir entre &lt;strong&gt;3 &amp;agrave; 4&amp;nbsp;DROPS ELEMENTAIS&amp;nbsp;&lt;/strong&gt;com Quantidades diferentes para cada DROP.&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;Haver&amp;aacute; uma chance de vir &lt;strong&gt;DROP GHOST no Conjunto!&lt;/strong&gt;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;Ent&amp;atilde;o treinador, pronto para encarar sua Sorte?!&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/013.png&quot; alt=&quot;013&quot; /&gt;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;&lt;em&gt;Conjunto de DROPS dispon&amp;iacute;vel at&amp;eacute; o final do Evento (18/05)!&lt;/em&gt;&lt;/strong&gt;&lt;/p&gt;', 1, '12/05/2019', b'1'),
(6, '[HOTFIX 1.2] Nota de HOTFIX  da Versão 1.2', '&lt;p style=&quot;text-align: center;&quot;&gt;Ol&amp;aacute; treinadores! Como v&amp;atilde;o?&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/002.png&quot; alt=&quot;002&quot; /&gt;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;Estamos aqui para inform&amp;aacute;-los sobre a &lt;strong&gt;HOTFIX&lt;/strong&gt; da&lt;strong&gt; Vers&amp;atilde;o 1.2&lt;/strong&gt; do&amp;nbsp;&lt;strong&gt;Pok&amp;eacute;mon World Legends!&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ol style=&quot;text-align: center;color:white;&quot;&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;O&amp;nbsp;&lt;strong&gt;Juiz&amp;nbsp;&lt;/strong&gt;estava passando por algumas dificuldades, como requirir&amp;nbsp;&lt;strong&gt;PREMIUM&amp;nbsp;&lt;/strong&gt;para acess&amp;aacute;-lo, e n&amp;oacute;s removemos isso. No entanto, para ter acesso &amp;agrave; ele &amp;eacute; necess&amp;aacute;rio&amp;nbsp;&lt;strong&gt;RANK 4 - TRAINER ou SUPERIOR.&lt;/strong&gt;&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;Alguns&amp;nbsp;&lt;strong&gt;MOVES&amp;nbsp;&lt;/strong&gt;estavam com os&amp;nbsp;&lt;strong&gt;TIPOS&lt;/strong&gt; errados, exemplo: &lt;strong&gt;Fusion Bolt,&amp;nbsp;&lt;/strong&gt;consertamos a maioria. Contudo, se algum estiver com este problema, reporte-os.&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;O&amp;nbsp;&lt;strong&gt;SERVIDOR&lt;/strong&gt; estava com o uso de cache bastante alto, contudo, otimizamos ele para uma maior fluidez.&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;Algumas&amp;nbsp;&lt;strong&gt;HABILIDADES&lt;/strong&gt; como &lt;strong&gt;Cloud Nine e Air Lock&lt;/strong&gt; n&amp;atilde;o estavam cancelando os outros&amp;nbsp;&lt;strong&gt;CLIMAS&lt;/strong&gt;, agora est&amp;atilde;o.&lt;/li&gt;\r\n&lt;/ol&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;Esse foi o fim do nosso&amp;nbsp;&lt;strong&gt;HOTFIX&lt;/strong&gt;.&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/010.png&quot; alt=&quot;010&quot; /&gt;&lt;br /&gt;&lt;strong&gt;AVISO:&amp;nbsp;&lt;/strong&gt;O jogo ainda est&amp;aacute; no come&amp;ccedil;o, passando por uma etapa de testes, principalmente no quesito de regulagem de pre&amp;ccedil;os e alguns&amp;nbsp;&lt;strong&gt;BUGS&lt;/strong&gt;,&lt;strong&gt;&amp;nbsp;&lt;/strong&gt;e estamos buscando melhorias. Por esse motivo reportem estes problemas pertinentes para n&amp;oacute;s!&amp;nbsp;&lt;br /&gt;&lt;br /&gt;&lt;strong&gt;Pok&amp;eacute;mon World Legends.&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/003.png&quot; alt=&quot;003&quot; /&gt;&lt;/strong&gt;&lt;/p&gt;', 1, '12/05/2019', b'1'),
(7, 'Notas de Atualização 1.3', '&lt;p style=&quot;text-align: center;&quot;&gt;Ol&amp;aacute; Treinadores! Como est&amp;atilde;o?&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;Sei que &lt;strong&gt;ningu&amp;eacute;m&lt;/strong&gt; perguntou, mas estou bem... bem cansado depois desta &lt;strong&gt;manunten&amp;ccedil;&amp;atilde;o&lt;/strong&gt;.&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/003.png&quot; alt=&quot;003&quot; /&gt;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;Mas vamos para o que interessa, as&amp;nbsp;&lt;strong&gt;Notas de Atualiza&amp;ccedil;&amp;otilde;es&amp;nbsp;&lt;/strong&gt;da Vers&amp;atilde;o 1.3!&lt;/p&gt;\r\n&lt;ol style=&quot;text-align: center;color:white;&quot;&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;Para aqueles que querem seus Pok&amp;eacute;mons ao estado inicial, nada melhor que a&amp;nbsp;&lt;strong&gt;Fonte da Juventude!&lt;/strong&gt; Confira!&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/013.png&quot; alt=&quot;013&quot; /&gt;&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;Corrigido alguns&amp;nbsp;&lt;strong&gt;BUGS&lt;/strong&gt;, como das&amp;nbsp;&lt;strong&gt;NOTIFICA&amp;Ccedil;&amp;Otilde;ES e Alguns Golpes.&lt;/strong&gt;&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;Removido&lt;/strong&gt; STARTER PACK para a Compra.&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/011.png&quot; alt=&quot;011&quot; /&gt;&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;Feito algumas &lt;strong&gt;M&lt;/strong&gt;&lt;strong&gt;elhorias Visuais e Otimiza&amp;ccedil;&amp;atilde;o do tempo&amp;nbsp;&lt;/strong&gt;ao final das batalhas.&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/012.png&quot; alt=&quot;012&quot; /&gt;&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;Adicionado [EVENTO]: &lt;em&gt;Zona do Safari!&lt;/em&gt;&lt;/strong&gt; Confiram!&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/007.png&quot; alt=&quot;007&quot; /&gt;&lt;/li&gt;\r\n&lt;/ol&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;At&amp;eacute; a &lt;strong&gt;P&lt;/strong&gt;&lt;strong&gt;r&amp;oacute;xima Treinadores!&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/014.png&quot; alt=&quot;014&quot; /&gt;&lt;/strong&gt;&lt;/p&gt;', 1, '08/06/2019', b'1'),
(8, 'Comemoração da vitória do Brasil!', '&lt;p style=&quot;text-align: center;&quot;&gt;Em comemora&amp;ccedil;&amp;atilde;o &amp;agrave; vit&amp;oacute;ria do&amp;nbsp;&lt;strong&gt;Brasil&lt;/strong&gt; na&amp;nbsp;&lt;strong&gt;Copa Am&amp;eacute;rica&lt;/strong&gt;, daremos &amp;agrave; todos os&amp;nbsp;&lt;strong&gt;Treinadores, 3 dias de VIP!&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/003.png&quot; alt=&quot;003&quot; /&gt;&lt;/strong&gt;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;Novidades em breve!&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/008.png&quot; alt=&quot;008&quot; /&gt;&lt;/strong&gt;&lt;/p&gt;', 1, '09/07/2019', b'0'),
(9, 'Notas de Atualização 1.4', '&lt;p style=&quot;text-align: center;&quot;&gt;Ol&amp;aacute; treinadores!&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/003.png&quot; alt=&quot;003&quot; /&gt;&lt;br /&gt;&lt;br /&gt;Depois de &lt;strong&gt;UM M&amp;Ecirc;S&amp;nbsp;&lt;/strong&gt;sem ter atualiza&amp;ccedil;&amp;otilde;es, estamos aqui para inform&amp;aacute;-los sobre...&lt;br /&gt;- Advinha o qu&amp;ecirc;?&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;- &lt;strong&gt;Novidades&lt;/strong&gt; da &lt;strong&gt;nova atualiza&amp;ccedil;&amp;atilde;o&lt;/strong&gt;!&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/008.png&quot; alt=&quot;008&quot; /&gt;&lt;br /&gt;&lt;br /&gt;Desta vez, fizemos muitas coisas pedidas por voc&amp;ecirc;s,&amp;nbsp;&lt;strong&gt;Treinadores&lt;/strong&gt;.&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/002.png&quot; alt=&quot;002&quot; /&gt;&lt;br /&gt;Esperamos que gostem!&lt;br /&gt;&lt;br /&gt;&lt;br /&gt;&lt;/p&gt;\r\n&lt;ol style=&quot;color:white;&quot;&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;Atualizamos&lt;/strong&gt; alguns &lt;strong&gt;TEXTOS&amp;nbsp;&lt;/strong&gt;com problemas de ortografia e avisos corrigidos.&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;BUG?&amp;nbsp;&lt;/strong&gt;N&amp;atilde;o o tipo Pok&amp;eacute;mon... alguns foram corrigidos!&amp;nbsp;&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/008.png&quot; alt=&quot;008&quot; /&gt;&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;Corrigido o problema com os &amp;iacute;cones Pok&amp;eacute;mon, que caso ele fosse renomeado, perderia o &amp;iacute;cone.&amp;nbsp;&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;Os&amp;nbsp;&lt;strong&gt;NPCs&lt;/strong&gt; que apareciam no mapa eram bem irritantes, ent&amp;atilde;o, diminuimos sua taxa de encontro com eles.&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/014.png&quot; alt=&quot;014&quot; /&gt;&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;O ganho de EXP&lt;/strong&gt; estava um pouco baixo, por isso resolvemos aument&amp;aacute;-lo um pouco.&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/016.png&quot; alt=&quot;016&quot; /&gt;&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;Os&amp;nbsp;&lt;strong&gt;TIERS&lt;/strong&gt; ou&amp;nbsp;&lt;strong&gt;RARIDADES&amp;nbsp;&lt;/strong&gt;dos Pok&amp;eacute;mon estavam confusas, portanto resolvemos expandi-las agora para&amp;nbsp;&lt;strong&gt;8 RARIDADES&lt;/strong&gt; para ficar o mais simplificado poss&amp;iacute;vel! (Sugest&amp;atilde;o de voc&amp;ecirc;s)&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/007.png&quot; alt=&quot;007&quot; /&gt;&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;Ajustamos&lt;/strong&gt; a&lt;strong&gt; TAXA DE CAPTURA&amp;nbsp;&lt;/strong&gt;de v&amp;aacute;rios Pok&amp;eacute;mon, que convenhamos, encontravam-se desbalanceadas.&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/005.png&quot; alt=&quot;005&quot; /&gt;&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;ADICIONAMOS&lt;/strong&gt; as&amp;nbsp;&lt;strong&gt;MISS&amp;Otilde;ES DI&amp;Aacute;RIAS (RANK 4 ou Superior)!&amp;nbsp;&lt;/strong&gt;Complete-as todos os dias para&amp;nbsp;&lt;strong&gt;ganhar&lt;/strong&gt; 1x&amp;nbsp;&lt;strong&gt;Master Ball&lt;/strong&gt;&amp;nbsp;por semana! Clique no &amp;iacute;cone do&amp;nbsp;&lt;strong&gt;ALVO COM A FLECHA&lt;/strong&gt;&amp;nbsp;na barra de alertas!&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/007.png&quot; alt=&quot;007&quot; /&gt;&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;EVENTO&amp;nbsp;&lt;/strong&gt;&lt;strong&gt;&lt;em&gt;FESTIVAL PIKACHU&lt;/em&gt;&amp;nbsp;&lt;/strong&gt;adicionado! Clique no bal&amp;atilde;o do EVENTO para mais detalhes!&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/018.png&quot; alt=&quot;018&quot; /&gt;&lt;/li&gt;\r\n&lt;/ol&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;UFA&lt;/strong&gt;...!&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/021.png&quot; alt=&quot;021&quot; /&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;Finalmentente encerramos a&amp;nbsp;&lt;strong&gt;NOTA DE ATUALIZA&amp;Ccedil;&amp;Atilde;O DA VERS&amp;Atilde;O 1.4!&lt;/strong&gt;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;Ent&amp;atilde;o? O que acharam? &lt;/strong&gt;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;Siga nossas redes sociais e participe do nosso grupo no Facebook, para estar atento &amp;agrave;s novidades&amp;nbsp;&lt;/strong&gt;&lt;strong&gt;e interagir com os Treinadores!&lt;/strong&gt;&lt;br /&gt;&lt;br /&gt;&lt;strong&gt;Link para o grupo:&lt;/strong&gt; https://www.facebook.com/groups/1384434638310435&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;&lt;em&gt;&lt;strong&gt;ATT. Equipe Pok&amp;eacute;mon World Legends&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/003.png&quot; alt=&quot;003&quot; /&gt;&lt;/strong&gt;&lt;/em&gt;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;&amp;nbsp;&lt;/p&gt;', 1, '16/07/2019', b'0'),
(10, '[HOTFIX 1.4] PATCH - CORREÇÃO DE PROBLEMAS', '&lt;p style=&quot;text-align: center;&quot;&gt;Esse&amp;nbsp;&lt;strong&gt;PATCH&amp;nbsp;&lt;/strong&gt;&lt;strong&gt;1.4&lt;/strong&gt; veio com uma s&amp;eacute;rie de novidades, mas infelizmente alguns problemas.&lt;br /&gt;E este&amp;nbsp;&lt;strong&gt;HOTFIX&amp;nbsp;&lt;/strong&gt;foi voltado para corre&amp;ccedil;&amp;atilde;o destes problemas e aproveitamos para averiguar os pendentes.&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/008.png&quot; alt=&quot;008&quot; /&gt;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;Ent&amp;atilde;o, vamos l&amp;aacute;!&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;CORRE&amp;Ccedil;&amp;Otilde;ES:&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ol style=&quot;color:white;&quot;&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;Nos&amp;nbsp;&lt;strong&gt;Comerciantes&lt;/strong&gt;, alguns Pok&amp;eacute;mons que n&amp;atilde;o deveriam aparecer estavam dispon&amp;iacute;veis...&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/020.png&quot; alt=&quot;020&quot; /&gt;&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;Os ataques:&amp;nbsp;&lt;strong&gt;Bounce, Fly, Dive e Dig&lt;/strong&gt;, tiveram suas funcionabilidades ajeitadas.&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;Havia um problema na&amp;nbsp;&lt;strong&gt;BOX&lt;/strong&gt; que bugava a troca de Pok&amp;eacute;mons nas batalhas, agora n&amp;atilde;o h&amp;aacute; mais!&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/016.png&quot; alt=&quot;016&quot; /&gt;&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;A&amp;nbsp;&lt;strong&gt;Fonte de Juventude PREMIUM&lt;/strong&gt; tinha um problema de verifica&amp;ccedil;&amp;atilde;o nos SLOTS dispon&amp;iacute;veis dos Treinadores.&lt;/li&gt;\r\n&lt;/ol&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;AJUSTES:&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ol style=&quot;color:white;&quot;&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;Diminuida&amp;nbsp;&lt;/strong&gt;a&amp;nbsp;&lt;strong&gt;CHANCE&lt;/strong&gt; de encontrar Pok&amp;eacute;mons Lend&amp;aacute;rios.&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/010.png&quot; alt=&quot;010&quot; /&gt;&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;As&amp;nbsp;&lt;strong&gt;MISS&amp;Otilde;ES DI&amp;Aacute;RIAS&lt;/strong&gt; agora t&amp;ecirc;m limite de uma&amp;nbsp;&lt;strong&gt;RECOMPENSA&lt;/strong&gt; por CONTA e n&amp;atilde;o mais por&amp;nbsp;&lt;strong&gt;PERSONAGEM.&amp;nbsp;&lt;/strong&gt;&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;Os&amp;nbsp;&lt;strong&gt;NPCs&amp;nbsp;&lt;/strong&gt;agora est&amp;atilde;o dando mais&amp;nbsp;&lt;strong&gt;SILVERS,&amp;nbsp;&lt;/strong&gt;quando derrotados (baseado em seu&amp;nbsp;&lt;strong&gt;RANK&lt;/strong&gt;).&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/003.png&quot; alt=&quot;003&quot; /&gt;&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;&amp;nbsp;Realizado&amp;nbsp;&lt;strong&gt;algumas&amp;nbsp;&lt;/strong&gt;&lt;strong&gt;melhorias&amp;nbsp;&lt;/strong&gt;&lt;strong&gt;VISUAIS.&amp;nbsp;&lt;/strong&gt;&lt;/li&gt;\r\n&lt;/ol&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;ADI&amp;Ccedil;&amp;Atilde;O:&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ol style=&quot;color:white;&quot;&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;TODAS&amp;nbsp;&lt;/strong&gt;as&amp;nbsp;&lt;strong&gt;Z-MOVES&amp;nbsp;&lt;/strong&gt;est&amp;atilde;o implementadas no jogo! Aguardem os pr&amp;oacute;ximos&amp;nbsp;&lt;strong&gt;EVENTOS&amp;nbsp;&lt;/strong&gt;para obt&amp;ecirc;-las!&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/013.png&quot; alt=&quot;013&quot; /&gt;&lt;/li&gt;\r\n&lt;/ol&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;Este foi o&amp;nbsp;&lt;strong&gt;HOTFIX da 1.4!&lt;/strong&gt;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;Siga nossas redes sociais e participe do nosso grupo no Facebook, para estar atento &amp;agrave;s novidades e interagir com os Treinadores! Link para o grupo: https://www.facebook.com/groups/1384434638310435 &lt;/strong&gt;&lt;/p&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;&lt;em&gt;&lt;strong&gt;ATT. Equipe Pok&amp;eacute;mon World Legends&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/003.png&quot; alt=&quot;003&quot; /&gt;&lt;/strong&gt;&lt;/em&gt;&lt;/p&gt;', 1, '18/07/2019', b'0'),
(11, '[PATCH 1.4.2] Atualização no PREMIUM, e um pouco mais.', '&lt;p style=&quot;color:white;text-align: center;&quot;&gt;&lt;strong&gt;Este foi um HOTFIX/ATUALIZA&amp;Ccedil;&amp;Atilde;O&amp;nbsp;&lt;/strong&gt;que ocorreram ao decorrer desta semana.&lt;/p&gt;\r\n&lt;ol style=&quot;color:white;&quot;&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;Adi&amp;ccedil;&amp;atilde;o da&amp;nbsp;&lt;strong&gt;Zona do Safari&lt;/strong&gt;, todas as Ter&amp;ccedil;as, Quintas e S&amp;aacute;bados.&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/005.png&quot; alt=&quot;005&quot; /&gt;&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;Corre&amp;ccedil;&amp;atilde;o das&amp;nbsp;&lt;strong&gt;TIPAGENS&lt;/strong&gt; dos Pok&amp;eacute;mon.&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;Melhoria em alguns algoritmos como o de&amp;nbsp;&lt;strong&gt;SAIR DE BATALHAS&amp;nbsp;&lt;/strong&gt;ou&amp;nbsp;&lt;strong&gt;CAPTURAR POK&amp;Eacute;MON&lt;/strong&gt;.&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;Adi&amp;ccedil;&amp;atilde;o do&amp;nbsp;&lt;strong&gt;Especialista em Humor Profissional&lt;/strong&gt;. O qual voc&amp;ecirc; pode escolher qual humor voc&amp;ecirc; gostaria de colocar em seu Pok&amp;eacute;mon.&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/007.png&quot; alt=&quot;007&quot; /&gt;&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;Atualiza&amp;ccedil;&amp;atilde;o dos&amp;nbsp;&lt;strong&gt;PREMIUM&lt;/strong&gt;:&amp;nbsp;&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/018.png&quot; alt=&quot;018&quot; /&gt;&lt;br /&gt;Agora, na Calculadora Simples, quem for PREMIUM poder&amp;aacute; us&amp;aacute;-la gratuitamente.&lt;br /&gt;Calculadora PREMIUM: 50% de desconto, passando a custar&amp;nbsp;&lt;strong&gt;5 Gold.&lt;/strong&gt;&lt;br /&gt;&lt;strong&gt;Viagens &lt;/strong&gt;com pre&amp;ccedil;o acima de 1.000 Silvers ser&amp;atilde;o travadas neste pre&amp;ccedil;o.&lt;br /&gt;&lt;strong&gt;Especialista em Nome&amp;nbsp;&lt;/strong&gt;ser&amp;aacute; gratuito.&lt;br /&gt;&lt;strong&gt;Especialista&amp;nbsp;&lt;/strong&gt;&lt;strong&gt;Shiny&amp;nbsp;&lt;/strong&gt;ter&amp;aacute; 25% de desconto.&lt;br /&gt;&lt;strong&gt;Especialista em Humores (Simples)&lt;/strong&gt;: 15% de desconto.&lt;br /&gt;&lt;br /&gt;&lt;/li&gt;\r\n&lt;li style=&quot;text-align: center;&quot;&gt;Houve uma melhoria no desempenho ao carregar as Sprites.&lt;br /&gt;&lt;br /&gt;&lt;/li&gt;\r\n&lt;/ol&gt;\r\n&lt;p style=&quot;text-align: center;&quot;&gt;Estamos &amp;agrave; procura de&amp;nbsp;&lt;strong&gt;BUGS&lt;/strong&gt;&amp;nbsp;e cientes de outros. Estamos tentando resolv&amp;ecirc;-los o mais r&amp;aacute;pido poss&amp;iacute;vel.&amp;nbsp;&lt;br /&gt;&lt;br /&gt;Att. Equipe Pok&amp;eacute;mon World Legends.&amp;nbsp;&lt;img src=&quot;../public/plugins/tinymce/plugins/emoticons/pokemoji/002.png&quot; alt=&quot;002&quot; /&gt;&lt;/p&gt;', 1, '25/08/2019', b'0');
