INSERT INTO `pokemon_icons` (`id`, `name`, `img`, `descr`, `rarity`) VALUES
(1, 'Cassino Pokémon', 'casino', 'Pokémon advindo do cassino.', 'Comum'),
(2, 'Halloween 2018', 'halloween1', 'Evento de Halloween 2018.', 'Ultra Raro'),
(3, 'FESTIVAL PIKACHU - JULHO 2019', 'pikachu_festival', 'Evento de CAPTURA E CAÇA DE PIKACHU, ONDE OS COSPLAY APARECIAM NO MAPA E O PRÊMIO MAIOR ERA A PIKANIUM Z, OCORRIDO EM JULHO DE 2019.', 'Ultra Raro'),
(4, 'DROPS ELEMENTAIS - MAIO 2019', 'ghost', 'Evento de DROPS ocorrido em MAIO DE 2019, onde o Prêmio maior era a Spooky Plate!', 'Raro'),
(5, 'TORNEIO BEST OF FIRE - 14/06/2019', 'torneio', '1º torneio do jogo, ocorrido no dia 14/06/2019 para Pokémons apenas do TIPO FOGO, onde o vencedor foi TonyStark.', 'Lend?rio'),
(6, 'TORNEIO STORM FURY - 28/06/2019', 'torneio', '2º torneio do jogo, ocorrido no dia 28/06/2019 para Pokémons apenas do TIPO ELÉTRICO, onde o vencedor foi Lonerson.', 'Lend?rio'),
(7, '1º TORNEIO SURPRESA (4x4) - 27/07/2019', 'torneio', '3º torneio do jogo e o 1º surpresa 4x4, ocorrido no dia 27/07/2019 para Pokémons LvL. 100, 4x4.', 'Lend?rio'),
(8, 'TORNEIO SHADOW FORCE - 15/08/2019', 'torneio', '4º torneio do jogo, ocorrido no dia 15/08/2019 para Pokémons apenas do TIPO FANTASMA, onde o vencedor foi Lonerson e o segundo lugar foi Raziel.', 'Lend?rio');
