INSERT INTO `traders` (`id`, `eigenaar`, `naam`, `wil`) VALUES
(1, 'Kayl', 'Tapu Fini', 'Moltres'),
(2, 'Wayne', 'Espurr', 'Magnemite'),
(3, 'Remy', 'Cresselia', 'Latias');
INSERT INTO `trainer` (`id`, `naam`, `image`, `badge`, `gymnaam`, `wereld`, `gebied`, `rank`, `prijs`, `descr`, `progress`) VALUES
(1, 'Brock', '', 'Boulder', 'Pewter', 'Kanto', '', 3, 500, 'Há alguns anos, o ginásio de <b>Pewter</b> foi abandonado. O ex-famoso treinador Flint sentia-se deprimido por atrair poucos alunos e decidiu tornar-se um Mestre Pokémon, obrigando deu filho <b>Brock</b> a tomar conta do ginásio de <b>Pewter</b>. Brock reergueu o ginásio, cuidou de seus nove irmãos e jamais deixou seus estudos e treinamentos de lado. <br> Este treinador é especializado no tipo: <b>Rock</b>.', 0),
(2, 'Misty', '', 'Cascade', 'Cerulean', 'Kanto', '', 3, 600, 'As <b>Irmãs Sensacionais</b> transformaram o ginásio num verdadeiro circo aquático. Com o tempo, elas perderam seus espíritos de treinadoras e começaram a distribuir suas insígnias para todos os treinadores que aparecessem. Com isso os outros líderes ficaram vendo o Ginásio de <b>Cerulean</b> com maus olhos. <br>Revoltada, <b>Misty</b>, a mais nova das irmãs, decidiu tornar-se uma treinadora Pokémon. <br>Este treinador é especializado no tipo: <b>Water</b>.', 1),
(3, 'Lt. Surge', '', 'Thunder', 'Vermilion', 'Kanto', '', 3, 700, 'Surge foi um soldado americano que lutou numa guerra, onde foi salvo pelos seus Pokémon Electric. <br>Sendo membro do exército, Surge é bastante prudente e estrito. Também é piloto, e usava os seus Pokémon para gerar energia para o seu avião. <br>Salvou a vida de um dos seus treinadores do seu Gym que também esteve na guerra. <br>É um pouco paranóico, por isso montou várias armadilhas no seu Gym. <br>Este treinador é especializado no tipo: <b>Electric</b>.', 2),
(4, 'Erika', '', 'Rainbow', 'Celadon', 'Kanto', '', 3, 800, 'Erika é muito responsável na criação de seus Pokémon e tendo os Tipo-Grama  como seus preferidos, fez do Ginásio de Celadon uma enorme estufa, onde  vivem confortavelmente. Foi inspirada a se tornar uma treinadora ainda  na infância, quando foi atacada por um Grimer, e um Gloom a defendeu,  tornando-se desde então, seu Pokémon mais querido. <br>Este treinador é especializado no tipo: <b>Grass</b>', 3),
(5, 'Sabrina', '', 'Marsh', 'Saffron', 'Kanto', '', 3, 900, 'Logo que identificou seus poderes, Sabrina ficou ainda mais obcecada por  seu desenvolvimento. Tornou-se solitária e cada vez menos emocional,  passando a usar suas habilidades para fins destrutivos ao ponto de  transformar sua mãe em uma boneca. Suas atitudes acabam lhe causando uma  ruptura psicológica e as emoções que tentava reprimir se manifestam em uma  personalidade à parte, uma garotinha, sua própria imagem quando criança,  que só quer se divertir e fazer amigos, bem diferente da mulher fria e com  sede de poder que Sabrina se tornara. <br>Este treinador é especializado no tipo: <b>Psychic</b>.', 4),
(6, 'Koga', '', 'Soul', 'Fuchsia', 'Kanto', '', 3, 1000, ' Koga tem um ginásio na Cidade de Fuchsia. Neste ponto ele deixa o ginásio,  que fica com sua filha, Janine. Koga torna-se membro da nova elite dos 4,  ele é um dos mestres pokémon. Ele aparece com uma nova equipe de pokémons  totalmente evoluídos. <br>Este treinador é especializado no tipo: <b>Poison e Bug </b>.', 5),
(7, 'Blaine', '', 'Volcano', 'Cinnabar', 'Kanto', '', 3, 1100, 'Na Juventude, Blaine trabalhou como engenheiro genético para a Equipe Rocket, mas, cansado das atrocidades cometidas, tomou parte na operação que  exterminou o grupo. Mais tarde, foi considerado herói após proteger o  pássaro lendário Moltres. Nomeado líder, usa seu ginásio como centro de pesquisas, revivendo Pokémon  extintos. Chateado com a invasão de turistas na ilha de Cinnabar, Blaine  fechou o seu ginásio e anda disfarçado pela cidade com óculos escuros e  peruca, já que é careca. Ele permanece com seu ginásio aberto dentro do  vulcão, fazendo charadas pela cidade, se for um treinador que quer mesmo  lutar a sério, ele chama para o ginásio para se divertir nessas lutas pela  insígnia. <br>Este treinador é especializado no tipo: <b>Fire</b>.', 6),
(8, 'Giovanni', '', 'Earth', 'Viridian', 'Kanto', '', 3, 1200, 'Giovanni é o rico e poderoso chefe da Equipe Rocket, responsável por  encabeçar os planos mais complexos da organização visando à obtenção e  controle total de Pokémon lendários, ou de imenso poder. <br>Este treinador é especializado no tipo: <b>Variados</b>.', 7),
(9, 'Falkner', '', 'Zephyr', 'Violet', 'Johto', '', 3, 500, '<b>Falkner</b> é um oficial de polícia que assumira o ginásio de Violet após seu pai o largar. <br> Aparece em Gold & Silver principalmente durante o ataque da Neo Equipe Rocket à Liga Pokémon e também em sua batalha contra Jeanine. <br>É um mestre Pokémon do tipo <b>Flying/Voador</b>.', 0),
(10, 'Bugsy', '', 'Hive', 'Azalea', 'Johto', '', 3, 600, '<b>Bugsy</b> é um explorador que se concentra seu trabalho nas ruínas de Johto. <br>Kurt construiu para ele uma Great Ball especial, que é posta sobre um bastão e sua rede interna de captura passa a ser externa e própria para a captura de Pokémons de Água/Water e Inseto/Bug. <br>Ele é especializado com Pokémon tipo <b>Inseto/Bug</b>.', 1),
(11, 'Whitney', '', 'Plain', 'Goldenrod', 'Johto', '', 3, 700, '<b>Whitney</b> é uma atriz gentil e sutil. <br>Ela é amiga de Mary, a locutora/DJ da rádio de Cherrygrove e acaba por ser a líder de Johto que mais participa na história. <br>Usa Pokémons do tipo <b>Normal</b>.', 2),
(12, 'Morty', '', 'Fog', 'Ecruteak', 'Johto', '', 3, 800, '<b>Morty</b> é uma espécie de clarividente que conseguir ter premonições aleatórias. Isso o ajuda a entender seus Pokémons.<br>Usa Pokémons do tipo <b>Ghost</b>', 3),
(13, 'Chuck', '', 'Storm', 'Cianwood', 'Johto', '', 3, 900, '<b>Chuck</b> é um lutador ávido. É treinado para lutar qualquer luta e vencê-la a todo custo. <br>Tem um grande amigo, Walker, que costuma batalhar com ele com seu Skarmory. <br>Chuck treinou Blue para as batalhas Pokémons quando ele era menor e quando Chuck respondia por jovem, Bruno, da Elite dos Quatro do Planalto Índigo, o treinou para ser deste jeito, apesar de que ele (Chuck) ser aparentemente mais velho que Bruno. <br>Ele treina Pokémons do tipo <b>Fighting</b> e seu Poliwrath é sua marca registrada.', 4),
(14, 'Jasmine', '', 'Mineral', 'Olivine', 'Johto', '', 3, 1000, '<b>Jasmine</b> é a líder misteriosa de Olivine. <br>Além de batalhar, também compete em Contests pelas regiões de Johto, Hoenn e Sinnoh. <br>Ela era especialista em tipo Rock, até que Crystal e o Professor Oak finalmente descobriram o tipo <b>Steel</b>. ', 5),
(15, 'Pryce', '', 'Glacier', 'Mahogany', 'Johto', '', 3, 1100, '<b>Pryce</b> é um velho aposentado, líder de ginásio de Mahogany. <br>Ele está preso a uma cadeira de rodas e bem raramente deixa seus aposentos. Sua cara familiar e gentil  na verdade é uma pura ilusão, já que por trás de toda esta fraqueza e fadiga há uma alma malévola e calculista. <br>Pryce é o antagonista da história, sendo então o Homem Mascarado, que tirou a infância de Silver, Blue e várias outras crianças traindo seu mestre, Giovanni, e construindo uma organização paralela que utilizava de seus membros corruptos. <br>Foi engolido pelo tempo a passar a eternidade viajando, até que Celebi o liberou e assim fez uma aliança com Giovanni e Lance para salvar Sinnoh e Johto. No final, acaba largando a maldade e voltando ao ginásio de <b>Mahogany</b>. Usa Pokemóns do tipo <b>Water</b> e <b>Ice</b>', 6),
(16, 'Clair', '', 'Rising', 'Blackthorn', 'Johto', '', 3, 1200, '<b>Clair</b> é prima de Lance e líder do ginásio de Blacktorn. <br>É especialista em <b>Dragon</b>, apesar de também ser boa com Pokémons de <b>Water</b>.', 7),
(17, 'Roxanne', '', 'Stone', 'Rustboro', 'Hoenn', '', 3, 500, '<b>Roxanne</b> é uma Estudante da Pokémon Trainer’s School. <br>Roxanne tornou-se a líder do ginásio de Rustboro para aprender mais sobre os Pokémon, por meio das batalhas, buscando a velha conciliação entre prática e teoria. <br>Especializada no tipo <b>Rock</b>, ela se destaca por ser a primeira mulher a se arriscar nesse terreno áspero.', 0),
(18, 'Brawly', '', 'Knuckle', 'Dewford', 'Hoenn', '', 3, 600, 'Junte todas as gírias de surfista a um homem que treina na cachoeira, buscando aguçar suas habilidades, este é <b>Brawly</b>. <br>Eis aí Brawly, que, na ausência de cachoeira, treina na Granite Cave mesmo assim. <br>Ele treinou com o Grande Bruno da Elite dos 4 de Kanto. <br>Seu ginásio é escuro, buscando aprimorar os sentidos dos desafiantes. Vale lembrar também que esse é um grande amigo de Steven. <br>Especializado no tipo <b>Fighting</b>.', 1),
(19, 'Wattson', '', 'Dynamo', 'Mauville', 'Hoenn', '', 3, 700, '<b>Wattson</b> um homem alegremente eletrizante. Não somente isso, é também um grande líder de ginásio, encarregado daquele que fica em Mauville. <br>Usa Pokémons do tipo <b>Electric</b>.', 2),
(20, 'Flannery', '', 'Heat', 'Lavaridge', 'Hoenn', '', 3, 800, 'Jovem, alta, esbelta e com cabelos ruivos, <b>Flannery</b> é uma das líderes preferidas. <br>Com paixão natural pelos tipo fogo, a bela tem a missão de assumir o ginásio de  Lavaridge, cidade no oeste de Hoenn conhecida pelas suas fontes quentes, embora tenha pouco tempo de experiência. <br>Ela sempre busca desempenhar a função da melhor  forma possível, lembrando um pouco seu avô, Mr. Moore, ex-líder de Lavaridge e antigo membro da Elite dos 4 de Hoenn, tentando convencer os desafiantes de sua força. <br>Usa Pokémons do tipo <b>Fire</b>.', 3),
(21, 'Norman', '', 'Balance', 'Petalburg', 'Hoenn', '', 3, 900, '<b>Norman</b> é calmo e concentrado e vive para os Pokémon e seu ginásio. <br>Usa Pokémons do tipo <b>Normal</b>.', 4),
(22, 'Winona', '', 'Feather', 'Fortree', 'Hoenn', '', 3, 1000, '<b>Winona</b> é apaixonada pelos céus e pelos Pokémon com asas. <br>Velha conhecida de Skyla, líder da cidade de Mistralton, em Unova, Winona gosta de sentir o calor das batalhas (diferindo da preguiçosa Skyla em uma passagem tenebrosa de sua vida), o vento nos longos cabelos e a adrenalina dos ares. <br>Usa Pokémons do tipo <b>Flying</b>.', 5),
(24, 'Wallace', '', 'Rain', 'Sootopolis', 'Hoenn', '', 3, 1100, 'Encarregado do ginásio de Sootopolis, uma ilha de paredes rochosas e naturais no meio da rota 126. <br>Uma estrela dos Pokémon Contests, <b>Wallace</b> conta com força, graça, estilo e Milotic, o segundo Pokémon mais esbelto de todos. <br>Usa Pokémons do tipo <b>Water</b>', 6),
(25, 'Roark', '', 'Coal', 'Oreburgh', 'Sinnoh', '', 3, 500, 'Roark é poderoso e muito inteligente, ajudou Dawn a ficar mais confiante e ficar mais poderosa com seus pokémon. É sábio e quando pequeno era orgulhoso e  odiava perder como Platinum, mas hoje ele é bem sucedido e aceita suas  derrotas. <br>Este treinador é especializado no tipo: <b>Rock</b>.', 0),
(26, 'Gardenia', '', 'Forest', 'Eterna', 'Sinnoh', '', 3, 600, 'Gardenia é a segunda Gym Leader de Sinnoh. Gardenia gosta de explorar a Eterna Forest, e ela aparece em frente ao Old Chateau, e falar sobre as misteriosas histórias de assombrações à volta da casa. Ela própria afirma que tem medo de fantasmas. Aparece as vezes na Villa, após a Houseplant ter sido comprada. <br>Este treinador é especializado no tipo: <b>Grass</b>.', 1),
(27, 'Maylene', '', 'Cobble', 'Veilstone', 'Sinnoh', '', 3, 700, 'Maylene é considerada como uma mocinha fofinha, mas os adultos da sua  cidade tem bastante respeito por ela e pelo seu poder. O seu pai joga no  Veilstone Game Corner. Aparentemente, Maylene não conhece a sua própria  força, e nem tem a certeza de como tornou-se na Gym Leader de Veilstone  City, que parece-lhe tudo muito confuso. <br>Este treinador é especializado no tipo: <b> Fighting</b>.', 2),
(28, 'Crasher Wake', '', 'Fen', 'Pastoria', 'Sinnoh', '', 3, 800, 'Wake tem uma personalidade jovial, entusiasta e bombástica. A sua estratégia  de combate é nada mais que escolher os ataques que farão com que as  batalhas sejam mais divertidas, e encoraja à todos para não levaram as batalhas tão a sério e que devem se lembrar de se divertirem. <br>Este treinador é especializado no tipo: <b>Water</b>.', 3),
(29, 'Fantina', '', 'Relic', 'Hearthome', 'Sinnoh', '', 3, 900, 'Fantina fala com uma mistura de Francês e Inglês. Ela é originária de outra  região, e quando chegou a Sinnoh, decidiu que queria tornar-se numa  Coordinator, por isso que ela veste-se com roupas extravagantes para os  Contests. <br>Este treinador é especializado no tipo: <b>Ghost</b>.', 4),
(30, 'Byron', '', 'Mine', 'Canavale', 'Sinnoh', '', 3, 1000, 'Ele é o pai do Gym Leader Roark e filho do Underground Man. Foi Byron que  pediu à Riley para ele tornar-se no Gym Leader de Oreburgh City, mas Riley  recusou porque acreditava que Roark deveria ser quem ocupasse esse lugar. <br>Este treinador é especializado no tipo: <b>Steel</b>.', 5),
(31, 'Candice', '', 'Icicle', 'Snowpoint', 'Sinnoh', '', 3, 1100, 'Candice ensina que antes de se batalhar com Pokémon, a pessoa precisa tornar-se amiga dele primeiro. Ela tem um grande interesse por fashion e romance, tal como Pokémon, acredita que as pessoas devem ter o seu foco no que querem fazer. <br>Este treinador é especializado no tipo: <b>Ice</b>.', 6),
(32, 'Volkner', '', 'Beacon', 'Sunnyshore', 'Sinnoh', '', 3, 1200, 'Volkner é o melhor amigo de Flint, e tornou-se um pouco abatido e depressivo por causa dos desafiantes indignos que tem aparecido para desafiá-lo em Sunyshore City. Volkner tem planeado desafiar a Elite 4 e passa grande parte do seu tempo renovando os equipamentos eléctricos do seu Gym, que são  uma das fontes de energia da cidade, mas que as vezes faz a energia ir-se  toda. <br>Este treinador é especializado no tipo: <b>Electric<b>.', 7),
